"use client";
import { useState } from "react";
type S = "idle"|"processing"|"done"|"error";
interface R { videoPath:string;title:string;emotion:string;duration:number;imageCount:number;cost:number; }
const EL:Record<string,string> = {funny:"😂 재밌음",touching:"🥹 감동",angry:"😤 분노",relatable:"🤝 공감"};

export default function Home() {
  const [tab,setTab]=useState<"image"|"manual">("image");
  const [st,setSt]=useState<S>("idle");
  const [prog,setProg]=useState<string[]>([]);
  const [res,setRes]=useState<R|null>(null);
  const [err,setErr]=useState("");
  const [files,setFiles]=useState<File[]>([]);
  const [dg,setDg]=useState(false);
  const [ti,setTi]=useState("");
  const [bo,setBo]=useState("");
  const [co,setCo]=useState([""]);

  const gen=async(fd:FormData)=>{
    setSt("processing");setProg([]);setRes(null);setErr("");
    try{
      const r=await fetch("/api/generate",{method:"POST",body:fd});
      const rd=r.body?.getReader();if(!rd)throw new Error("fail");
      const d=new TextDecoder();
      while(true){const{done,value}=await rd.read();if(done)break;
        for(const l of d.decode(value).split("\n").filter(x=>x.startsWith("data: "))){
          try{const j=JSON.parse(l.slice(6));
            if(j.type==="progress")setProg(p=>[...p,j.message]);
            else if(j.type==="done"){setRes(j.result);setSt("done");}
            else if(j.type==="error")throw new Error(j.message);
          }catch(e:any){if(!e.message?.includes("JSON"))throw e;}
        }
      }
    }catch(e:any){setErr(e.message);setSt("error");}
  };
  const reset=()=>{setSt("idle");setRes(null);setProg([]);setFiles([]);setErr("");};

  if(st==="processing")return(
    <main className="max-w-2xl mx-auto px-4 py-8">
      <div className="text-center py-8"><div className="text-5xl mb-4 animate-bounce">🎬</div>
      <h2 className="text-xl font-bold mb-2">영상 생성 중...</h2>
      <p className="text-gray-400">{prog[prog.length-1]||"준비 중..."}</p></div>
      <div className="w-full bg-gray-800 rounded-full h-2 mb-4">
        <div className="bg-blue-600 h-2 rounded-full transition-all duration-500" style={{width:`${Math.min((prog.length/8)*100,95)}%`}}/></div>
      <div className="bg-gray-900 rounded-lg p-4 max-h-64 overflow-y-auto">
        {prog.map((m,i)=>(<div key={i} className="flex gap-2 py-1 text-sm"><span className="text-green-400">✓</span><span className="text-gray-300">{m}</span></div>))}
        <div className="flex gap-2 py-1 text-sm"><span className="text-yellow-400 animate-pulse">●</span><span className="text-gray-500">처리 중...</span></div>
      </div></main>);

  if(st==="done"&&res){const u=`/api/download?path=${encodeURIComponent(res.videoPath)}`;return(
    <main className="max-w-2xl mx-auto px-4 py-8">
      <div className="text-center mb-6"><div className="text-5xl mb-3">🎉</div><h2 className="text-2xl font-bold">영상 생성 완료!</h2></div>
      <div className="bg-gray-900 rounded-xl flex justify-center mb-6"><video src={u} controls className="max-h-[500px]" style={{aspectRatio:"9/16",maxWidth:"300px"}}/></div>
      <div className="bg-gray-800 rounded-lg p-4 space-y-2 text-sm mb-6">
        <div className="flex justify-between"><span className="text-gray-400">제목</span><span>{res.title}</span></div>
        <div className="flex justify-between"><span className="text-gray-400">감정</span><span>{EL[res.emotion]||res.emotion}</span></div>
        <div className="flex justify-between"><span className="text-gray-400">길이</span><span>{res.duration}초</span></div>
        <div className="flex justify-between"><span className="text-gray-400">만화</span><span>{res.imageCount}장</span></div>
        <div className="flex justify-between"><span className="text-gray-400">GPT API</span><span className="text-green-400">${res.cost.toFixed(3)}</span></div>
      </div>
      <div className="flex gap-3">
        <a href={u} download className="flex-1 py-3 bg-blue-600 hover:bg-blue-500 rounded-lg font-medium text-center">⬇️ 다운로드</a>
        <button onClick={reset} className="flex-1 py-3 bg-gray-700 hover:bg-gray-600 rounded-lg font-medium">🔄 새로 만들기</button>
      </div></main>);}

  return(
    <main className="max-w-2xl mx-auto px-4 py-8">
      <header className="text-center mb-8"><h1 className="text-3xl font-bold mb-2">ContentsMaker</h1>
        <p className="text-gray-400">블라인드 인기글 → 만화 쇼츠 자동 생성</p></header>
      <div className="flex gap-2 mb-6">
        {(["image","manual"] as const).map(t=>(<button key={t} onClick={()=>setTab(t)}
          className={`flex-1 py-3 rounded-lg font-medium transition ${tab===t?"bg-blue-600":"bg-gray-800 text-gray-400 hover:bg-gray-700"}`}>
          {t==="image"?"📸 스크린샷 업로드":"✏️ 직접 입력"}</button>))}
      </div>
      {tab==="image"?(<div>
        <div onDragOver={e=>{e.preventDefault();setDg(true)}} onDragLeave={()=>setDg(false)}
          onDrop={e=>{e.preventDefault();setDg(false);setFiles(p=>[...p,...Array.from(e.dataTransfer.files).filter(f=>f.type.startsWith("image/"))])}}
          onClick={()=>document.getElementById("fi")?.click()}
          className={`border-2 border-dashed rounded-xl p-8 text-center cursor-pointer transition ${dg?"border-blue-500 bg-blue-500/10":"border-gray-600 hover:border-gray-500"}`}>
          <div className="text-4xl mb-3">📸</div><p className="text-lg font-medium mb-1">블라인드 스크린샷을 드래그하세요</p>
          <p className="text-gray-500 text-sm">또는 클릭하여 파일 선택</p>
          <input id="fi" type="file" accept="image/*" multiple onChange={e=>{if(e.target.files)setFiles(p=>[...p,...Array.from(e.target.files!)])}} className="hidden"/></div>
        {files.length>0&&(<div className="mt-4 space-y-2">
          {files.map((f,i)=>(<div key={i} className="flex items-center justify-between bg-gray-800 rounded-lg px-4 py-2">
            <span className="text-sm truncate">{f.name}</span>
            <button onClick={()=>setFiles(files.filter((_,j)=>j!==i))} className="text-red-400 ml-2">✕</button></div>))}
          <button onClick={()=>{const fd=new FormData();fd.set("mode","image");files.forEach(f=>fd.append("images",f));gen(fd);}}
            className="w-full mt-4 py-3 bg-blue-600 hover:bg-blue-500 rounded-lg font-medium">🎬 영상 생성 ({files.length}장)</button></div>)}</div>
      ):(<div className="space-y-4">
        <div><label className="block text-sm text-gray-300 mb-1">제목 *</label>
          <input value={ti} onChange={e=>setTi(e.target.value)} placeholder="제목" className="w-full px-4 py-3 bg-gray-800 border border-gray-700 rounded-lg focus:border-blue-500 focus:outline-none"/></div>
        <div><label className="block text-sm text-gray-300 mb-1">본문 *</label>
          <textarea value={bo} onChange={e=>setBo(e.target.value)} placeholder="본문" rows={8} className="w-full px-4 py-3 bg-gray-800 border border-gray-700 rounded-lg focus:border-blue-500 focus:outline-none resize-y"/></div>
        <div><label className="block text-sm text-gray-300 mb-1">댓글</label>
          {co.map((c,i)=>(<div key={i} className="flex gap-2 mb-2">
            <input value={c} onChange={e=>{const u=[...co];u[i]=e.target.value;setCo(u)}} placeholder={`댓글${i+1}`} className="flex-1 px-4 py-2 bg-gray-800 border border-gray-700 rounded-lg text-sm focus:border-blue-500 focus:outline-none"/>
            {co.length>1&&<button onClick={()=>setCo(co.filter((_,j)=>j!==i))} className="text-red-400 px-2">✕</button>}</div>))}
          <button onClick={()=>setCo([...co,""])} className="text-sm text-blue-400">+ 댓글 추가</button></div>
        <button onClick={()=>{if(!ti.trim()||!bo.trim())return;const fd=new FormData();fd.set("mode","manual");fd.set("title",ti);fd.set("body",bo);fd.set("comments",JSON.stringify(co.filter(c=>c.trim())));gen(fd);}}
          disabled={!ti.trim()||!bo.trim()} className={`w-full py-3 rounded-lg font-medium ${ti.trim()&&bo.trim()?"bg-blue-600 hover:bg-blue-500":"bg-gray-700 text-gray-500 cursor-not-allowed"}`}>
          🎬 영상 생성</button></div>)}
      {err&&<div className="mt-4 p-4 bg-red-900/50 border border-red-500 rounded-lg text-red-200">{err}</div>}
    </main>);
}
